    Palette {
        name: "catppuccin-latte",
        accent: rgb(30, 102, 245), panel_bg: rgb(239, 241, 245),
        surface0: rgb(204, 208, 218), surface1: rgb(188, 192, 204), surface_dim: rgb(230, 233, 239),
        overlay0: rgb(156, 160, 176), overlay1: rgb(140, 143, 161),
        text: rgb(76, 79, 105), subtext0: rgb(108, 111, 133), mauve: rgb(136, 57, 239),
        green: rgb(64, 160, 43), yellow: rgb(223, 142, 29), red: rgb(210, 15, 57),
        blue: rgb(30, 102, 245), teal: rgb(23, 146, 153), peach: rgb(254, 100, 11),
